SELECT data_id
FROM county_health_data
WHERE county_id = 0;

SELECT program_name, description, 'active' AS program_status 
FROM health_programs 
WHERE status = 'active';

SELECT contact_email
FROM counties
WHERE median_income < 50000;

SELECT indicator_name 
FROM health_indicators 
WHERE indicator_id = 3;

SELECT user_id FROM users
EXCEPT
SELECT user_id FROM user_role_assignments;
